import {
  Table,
  Button,
  Modal,
  Form,
  Input,
  message,
} from 'antd';

import {
  useState,
  useEffect,
} from 'react';

import {
  getUniversities,
  createUniversity,
  deleteUniversity,
} from '@/services/university';

export default function UniversityPage() {
  const [data, setData] =
