                  )
                }
              >
                Xóa
              </Button>
            ),
          },
        ]}
      />

      <Modal
        title="Thêm trường"
        open={open}
        footer={null}
        onCancel={() =>
          setOpen(false)
        }
      >
        <Form
          form={form}
          layout="vertical"
          onFinish={
            handleCreate
          }
        >
          <Form.Item
            name="name"
            label="Tên trường"
            rules={[
              {
                required:
                  true,
              },
            ]}
          >
            <Input />
          </Form.Item>

          <Form.Item
            name="description"
            label="Mô tả"
          >
            <Input.TextArea />
          </Form.Item>

          <Button
            type="primary"
            htmlType="submit"
            block
          >
            Lưu
          </Button>
        </Form>
      </Modal>
    </div>
  );
}

